def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        penalty_factor = 1.0
        if usage_ratio > 2:
            priority += 3000 * (usage_ratio ** 1.3)
            penalty_factor = 2.5
        elif usage_ratio > 1:
            priority += 1800 * usage_ratio
            penalty_factor = 2.0
        elif usage_ratio == 1:
            priority += 250
        else:
            try:
                val = 1 - usage_ratio
                log_val = np.log(val + 1e-20)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -3:
                priority += (-log_val) * 15
            elif log_val < -1.5:
                priority += (-log_val) * 9
            else:
                priority += (-log_val) * 4
            extra = 0
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.3:
                    extra += power * 20 / (j**1.1)
                    if j % 3 == 0:
                        extra += 2 * j
                else:
                    extra += (1 - power) * 10 / (j + 2)
                    if j == 4 and usage_ratio > 0.6:
                        extra += 7
                if j == 5 and usage_ratio > 0.8:
                    extra += 9
            priority += extra
        if capacity < 0.01:
            priority += 150 * penalty_factor
            if usage_ratio > 0.8:
                priority += 60
            elif usage_ratio < 0.25:
                priority -= 30
        elif capacity < 0.25:
            priority += 50 * penalty_factor
            if usage_ratio > 0.9:
                priority += 35
            elif usage_ratio < 0.15:
                priority -= 15
        elif capacity < 0.7:
            if usage_ratio < 0.3:
                priority -= 20
            elif usage_ratio > 0.85:
                priority += 45
            else:
                priority += 20
        else:
            if usage_ratio < 0.15:
                priority -= 25
            elif usage_ratio > 0.92:
                priority += 50
            else:
                priority += 10
        proximity_score = 0
        if capacity % 3 == 0:
            proximity_score += 5
        if int(capacity * 9) % 4 == 0:
            proximity_score -= 4
        if int(capacity * 50) % 11 == 0:
            proximity_score += 8
        for k in range(1, 7):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.03:
                proximity_score += 15 / k
            elif diff < 0.08:
                proximity_score += 7 / k
        for m in range(1, 5):
            mod_check = (int(capacity * 1000)) % (m + 5)
            if mod_check == 0:
                proximity_score += m * 3
            elif mod_check == 2:
                proximity_score -= m * 1.5
            elif mod_check == 1 and m == 3:
                proximity_score += 4
        priority += proximity_score
        if usage_ratio < 0.03:
            for n in range(1, 5):
                priority -= n * 5
        elif usage_ratio > 0.97:
            for p in range(1, 5):
                priority += p * 6
        mixed_term = 0
        for q in range(1, 5):
            mixed_term += ((capacity ** 0.5) * (usage_ratio ** (q/4))) / (q + 1)
            if q % 2 == 1 and usage_ratio > 0.5:
                mixed_term += q * 2
            elif q % 2 == 0 and capacity < 0.5:
                mixed_term -= q * 1.5
        priority += mixed_term
        if capacity > 5:
            ceiled = np.ceil(capacity)
            floored = np.floor(capacity)
            diff = ceiled - capacity
            if diff < 0.1:
                priority += 10
            if int(floored) % 2 == 1:
                priority -= 7
        priorities[i] = priority
    return priorities
